const items = $input.all();
const emails = $('Rate Limit Wait').all();
const staticData = $getWorkflowStaticData('global');
if (!staticData.actionKeys) staticData.actionKeys = {};

return items.map((item, i) => {
  const raw = item.json.content[0].text.trim();
  const pipeIndex = raw.indexOf('|');
  const classification = pipeIndex !== -1 ? raw.substring(0, pipeIndex).trim() : raw;
  const summary = pipeIndex !== -1 ? raw.substring(pipeIndex + 1).trim() : '';

  const original = (emails[i] ?? { json: {} }).json;

  const actionKey = Math.random().toString(36).substring(2, 10);
  staticData.actionKeys[actionKey] = original.id;

  console.log('Classification:', classification, '| From:', original.from, '| Subject:', original.subject);
  return {
    json: {
      classification,
      summary,
      id: original.id,
      from: original.from?.emailAddress?.name || original.from?.emailAddress?.address || (typeof original.from === 'string' ? original.from : 'Unknown'),
      subject: original.subject,
      actionKey
    }
  };
});

